// scripts/firebase/guillotine-inflate-stats.js
// Reads the CSV files generated by guillotine-stats-to-csv.js and produces
// inflated versions in the same directory.
//
// ⚙️  Adjust INFLATION_FACTOR below to try different multipliers.
//
// Usage: node scripts/firebase/guillotine-inflate-stats.js

import { readFileSync, writeFileSync, existsSync } from "fs";
import { fileURLToPath } from "url";
import { dirname, join } from "path";
import chalk from "chalk";
import Table from "cli-table3";
import { createProgressBar } from "../shared/utils.js";

// ---------------------------------------------------------------------------
// ⚙️  CONFIGURATION
// ---------------------------------------------------------------------------

/** Multiply headCount, gamesStarted, and scoresShared by this factor. */
const INFLATION_FACTOR = 1.25;

// ---------------------------------------------------------------------------
// File paths
// ---------------------------------------------------------------------------

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const CSV_DIR = join(__dirname, "../csv/stats");
const HEADS_CSV = join(CSV_DIR, "guillotine-heads.csv");
const STATS_CSV = join(CSV_DIR, "guillotine-stats.csv");
const MISSING_FIELDS_JSON = join(CSV_DIR, "guillotine-missing-fields.json");

// Output files — overwritten every run (no versioning needed)
const INFLATED_HEADS_CSV = join(CSV_DIR, "guillotine-heads-inflated.csv");
const INFLATED_STATS_CSV = join(CSV_DIR, "guillotine-stats-inflated.csv");

// ---------------------------------------------------------------------------
// CSV helpers
// ---------------------------------------------------------------------------

function parseCSVLine(line) {
  const fields = [];
  let current = "";
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (ch === "," && !inQuotes) {
      fields.push(current);
      current = "";
    } else {
      current += ch;
    }
  }
  fields.push(current);
  return fields;
}

function parseCSV(content) {
  const lines = content.trim().split("\n");
  const headers = parseCSVLine(lines[0]);
  return lines.slice(1).map((line) => {
    const values = parseCSVLine(line);
    const obj = {};
    headers.forEach((h, i) => (obj[h.trim()] = values[i] !== undefined ? values[i].trim() : ""));
    return obj;
  });
}

function escapeCSV(value) {
  if (value === null || value === undefined) return "";
  const str = String(value);
  if (str.includes(",") || str.includes('"') || str.includes("\n")) {
    return `"${str.replace(/"/g, '""')}"`;
  }
  return str;
}

function toCSVString(rows, columns) {
  const header = columns.join(",");
  const lines = rows.map((row) => columns.map((col) => escapeCSV(row[col])).join(","));
  return [header, ...lines].join("\n") + "\n";
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

function main() {
  console.log(chalk.bold.blue("\n📈 Guillotine Stats Inflator\n"));
  console.log(chalk.gray(`   Inflation factor: ${chalk.bold.yellow(INFLATION_FACTOR)}x\n`));

  // -------------------------------------------------------------------------
  // 1. Validate that source CSVs exist and are usable
  // -------------------------------------------------------------------------
  const errors = [];

  if (!existsSync(HEADS_CSV)) {
    errors.push(`Missing source file: ${HEADS_CSV}`);
  }
  if (!existsSync(STATS_CSV)) {
    errors.push(`Missing source file: ${STATS_CSV}`);
  }

  if (errors.length > 0) {
    console.log(chalk.red("❌ Cannot inflate — required CSV files are missing:\n"));
    errors.forEach((e) => console.log(chalk.red(`   • ${e}`)));
    console.log(chalk.yellow("\n   Run guillotine-stats-to-csv.js first to generate source files."));
    process.exit(1);
  }

  // Block if the missing-fields report exists and has entries
  if (existsSync(MISSING_FIELDS_JSON)) {
    const missingData = JSON.parse(readFileSync(MISSING_FIELDS_JSON, "utf8"));
    if (Array.isArray(missingData) && missingData.length > 0) {
      console.log(chalk.red(`❌ Cannot inflate — ${missingData.length} head record(s) have missing fields.\n`));
      console.log(chalk.yellow(`   Review: ${MISSING_FIELDS_JSON}`));
      console.log(chalk.gray("   Resolve the data issues, re-run guillotine-stats-to-csv.js, then try again."));
      process.exit(1);
    }
  }

  // -------------------------------------------------------------------------
  // 2. Parse source CSVs
  // -------------------------------------------------------------------------
  console.log(chalk.yellow("📂 Reading source CSV files..."));

  const headRows = parseCSV(readFileSync(HEADS_CSV, "utf8"));
  const statsRows = parseCSV(readFileSync(STATS_CSV, "utf8"));

  if (headRows.length === 0) {
    console.log(chalk.red("❌ guillotine-heads.csv has no data rows. Re-run guillotine-stats-to-csv.js."));
    process.exit(1);
  }
  if (statsRows.length === 0) {
    console.log(chalk.red("❌ guillotine-stats.csv has no data rows. Re-run guillotine-stats-to-csv.js."));
    process.exit(1);
  }

  // Validate that headCount and netWorth are numeric for all rows
  const invalidRows = headRows.filter((row) => row.headCount === "" || row.netWorth === "" || isNaN(Number(row.headCount)) || isNaN(Number(row.netWorth)));
  if (invalidRows.length > 0) {
    console.log(chalk.red(`❌ ${invalidRows.length} row(s) have non-numeric headCount or netWorth:\n`));
    invalidRows.slice(0, 5).forEach((row) => {
      console.log(chalk.red(`   • "${row.name}": headCount="${row.headCount}", netWorth="${row.netWorth}"`));
    });
    if (invalidRows.length > 5) {
      console.log(chalk.red(`   ... and ${invalidRows.length - 5} more.`));
    }
    process.exit(1);
  }

  console.log(chalk.green(`   ✅ ${headRows.length} head records loaded.`));
  console.log(chalk.green(`   ✅ Stats document loaded.\n`));

  // -------------------------------------------------------------------------
  // 3. Inflate heads and accumulate new wealthCreated
  // -------------------------------------------------------------------------
  console.log(chalk.yellow(`⚙️  Inflating ${headRows.length} head records by ${INFLATION_FACTOR}x...\n`));

  let newTotalWealthCreated = 0;
  const inflatedHeadRows = [];

  const bar = createProgressBar("Inflating heads");
  bar.start(headRows.length, 0);

  for (let i = 0; i < headRows.length; i++) {
    const row = headRows[i];
    const originalHeadCount = Number(row.headCount);
    const netWorth = Number(row.netWorth);
    const inflatedHeadCount = Math.round(originalHeadCount * INFLATION_FACTOR);

    newTotalWealthCreated += inflatedHeadCount * netWorth;

    inflatedHeadRows.push({
      name: row.name,
      headCount: inflatedHeadCount,
      lastRemoved: row.lastRemoved,
      netWorth: row.netWorth,
    });

    bar.increment();
  }
  bar.stop();

  // -------------------------------------------------------------------------
  // 4. Inflate stats document fields
  // -------------------------------------------------------------------------
  const statsRow = statsRows[0];
  const originalGamesStarted = Number(statsRow.gamesStarted);
  const originalScoresShared = Number(statsRow.scoresShared);
  const originalGamesFinished = Number(statsRow.gamesFinished);
  const originalWealthCreated = Number(statsRow.wealthCreated);

  const newGamesStarted = Math.round(originalGamesStarted * INFLATION_FACTOR);
  const newGamesFinished = Math.round(newGamesStarted * 0.9);
  const newScoresShared = Math.round(originalScoresShared * INFLATION_FACTOR);
  const newWealthCreated = Math.round(newTotalWealthCreated);

  const inflatedStatsRow = {
    gamesFinished: newGamesFinished,
    gameLastFinished: statsRow.gameLastFinished,
    gamesStarted: newGamesStarted,
    lastGameStarted: statsRow.lastGameStarted,
    scoresShared: newScoresShared,
    wealthCreated: newWealthCreated,
  };

  // -------------------------------------------------------------------------
  // 5. Write inflated CSVs
  // -------------------------------------------------------------------------
  const HEAD_COLUMNS = ["name", "headCount", "lastRemoved", "netWorth"];
  const STATS_COLUMNS = ["gamesFinished", "gameLastFinished", "gamesStarted", "lastGameStarted", "scoresShared", "wealthCreated"];

  writeFileSync(INFLATED_HEADS_CSV, toCSVString(inflatedHeadRows, HEAD_COLUMNS), "utf8");
  writeFileSync(INFLATED_STATS_CSV, toCSVString([inflatedStatsRow], STATS_COLUMNS), "utf8");

  console.log(chalk.green(`\n✅ Wrote inflated heads to:`));
  console.log(chalk.gray(`   ${INFLATED_HEADS_CSV}`));
  console.log(chalk.green(`✅ Wrote inflated stats to:`));
  console.log(chalk.gray(`   ${INFLATED_STATS_CSV}`));

  // -------------------------------------------------------------------------
  // 6. Summary comparison table
  // -------------------------------------------------------------------------
  const summaryTable = new Table({
    head: [chalk.white("Field"), chalk.white("Before"), chalk.white("After"), chalk.white("Rule")],
    style: { head: [] },
  });

  summaryTable.push([chalk.bold("— Stats Document —"), "", "", ""]);
  summaryTable.push(["gamesStarted", originalGamesStarted.toLocaleString(), chalk.green(newGamesStarted.toLocaleString()), `×${INFLATION_FACTOR}`]);
  summaryTable.push(["gamesFinished", originalGamesFinished.toLocaleString(), chalk.green(newGamesFinished.toLocaleString()), "90% of started"]);
  summaryTable.push(["scoresShared", originalScoresShared.toLocaleString(), chalk.green(newScoresShared.toLocaleString()), `×${INFLATION_FACTOR}`]);
  summaryTable.push(["wealthCreated", originalWealthCreated.toLocaleString(), chalk.green(newWealthCreated.toLocaleString()), "recalculated"]);

  summaryTable.push([chalk.bold("— Heads Sample (5) —"), "", "", ""]);
  const sampleSize = Math.min(5, headRows.length);
  const step = Math.floor(headRows.length / sampleSize);
  for (let i = 0; i < sampleSize; i++) {
    const idx = i * step;
    const orig = Number(headRows[idx].headCount);
    const infl = inflatedHeadRows[idx].headCount;
    summaryTable.push([headRows[idx].name.slice(0, 28), orig.toLocaleString(), chalk.green(infl.toLocaleString()), `×${INFLATION_FACTOR}`]);
  }

  console.log("\n" + summaryTable.toString());
  console.log(chalk.bold.green("\n✅ Inflation complete!\n"));
  console.log(chalk.gray("   Review the CSVs, then run: node scripts/firebase/guillotine-csv-to-firestore.js\n"));
}

main();
